            package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch processes product search requests, logs analytics, 
// and displays the search keyword safely in the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search event
	if keyword != "" {
		log.Printf("[Analytics] Search performed - Keyword: %q, RemoteAddr: %s, UserAgent: %s", 
			keyword, r.RemoteAddr, r.UserAgent())
	}

	// Escape the keyword to prevent Cross-Site Scripting (XSS) vulnerabilities
	safeKeyword := html.EscapeString(keyword)

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the required HTML output
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler function to the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Define the port to listen on
	port := ":8080"
	log.Printf("Server starting on http://localhost%s", port)
	log.Printf("Try visiting: http://localhost%s/search?keyword=golang", port)

	// Start the HTTP server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

