// HandleProductSearch handles the product search results page.
// It extracts the keyword, logs it for analytics, and returns an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search event (can be expanded to send to an analytics service)
	if keyword != "" {
		log.Printf("[Analytics] Search performed for keyword: %q", keyword)
	} else {
		log.Println("[Analytics] Search performed with empty keyword")
	}

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Sanitize the keyword to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Write the formatted HTML to the response
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Starting server on port %s...", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

