            package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch processes product search requests and returns an HTML results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log the search event
	// In a real application, this might send data to an analytics service or database
	log.Printf("Analytics Event: Search performed. Keyword: %q, IP: %s, UserAgent: %s", 
		keyword, r.RemoteAddr, r.UserAgent())

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Write the HTML response with the required format
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler function
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s/search?keyword=example...", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

