            package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles the product search requests.
// It extracts the "keyword" query parameter, escapes it to prevent XSS,
// and returns an HTML response displaying the search keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract the search keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the user input to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Write the formatted HTML response
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler function for the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	fmt.Printf("Server is running on http://localhost%s/search?keyword=golang\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

