// HandleProductSearch processes the product search request, logs analytics, 
// and returns an HTML response with the search keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search event
	// In a real-world scenario, this could be sent to an analytics service or database.
	if keyword != "" {
		log.Printf("[Analytics] Search executed for keyword: %q", keyword)
	} else {
		log.Printf("[Analytics] Search executed with no keyword provided")
	}

	// 3. Prevent Cross-Site Scripting (XSS) by escaping the user input
	safeKeyword := html.EscapeString(keyword)

	// 4. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Write the response in the requested format
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler
