import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch processes the product search request, logs analytics, 
// and returns an HTML response displaying the search keyword safely.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the "keyword" query parameter from the URL
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log the search keyword for tracking purposes
	if keyword != "" {
		log.Printf("Analytics - Search event recorded for keyword: %q", keyword)
	}

	// Set the Content-Type header to indicate an HTML response
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS) vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Write the formatted HTML response
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", escapedKeyword)
}

func main() {
	// Register the handler to a route
	http.HandleFunc("/search", HandleProductSearch)

	// Define the port and start the HTTP server
	port := ":8080"
	log.Printf("Server is running on http://localhost%s", port)
	log.Printf("Try visiting: http://localhost%s/search?keyword=golang", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

