package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests, logs analytics, and displays the keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search event with the keyword and current time
	log.Printf("Analytics Event - Search triggered | Keyword: %q | Time: %s\n", keyword, time.Now().Format(time.RFC3339))

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the user input to prevent Cross-Site Scripting (XSS) vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Display the user's search keyword in the page title area
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", escapedKeyword)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server is starting on port %s...\n", port)
	log.Printf("Test the endpoint at: http://localhost%s/search?keyword=golang\n", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

