func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log the search event
	// In a real-world application, this might write to an analytics database or event stream.
	if keyword != "" {
		log.Printf("[Analytics] Search performed for keyword: %s", keyword)
	} else {
		log.Printf("[Analytics] Search performed with empty keyword")
	}

	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Sanitize the user input to prevent Cross-Site Scripting (XSS) attacks
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	// Write the HTTP status code and the HTML response
	w.WriteHeader(http.StatusOK)
	w.Write([]byte(htmlContent))
}

func main() {
	// Register the handler function
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server is starting on port %s...", port)
	log.Printf("Test the endpoint at: http://localhost%s/search?keyword=golang", port)

