            package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search requests, logs analytics, and displays the results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Ensure the response content type is set to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search event (could be sent to an external analytics service)
	if keyword != "" {
		log.Printf("[Analytics] Search Event - Keyword: %q, Timestamp: %s, IP: %s\n", 
			keyword, time.Now().Format(time.RFC3339), r.RemoteAddr)
	}

	// Sanitize the keyword to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Write the formatted HTML response
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler function to a route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	log.Println("Server is running on http://localhost:8080/search?keyword=golang")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v\n", err)
	}
}

