// HandleProductSearch is an HTTP handler that displays product search results.
// It extracts the "keyword" query parameter and safely renders it in the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent Cross-Site Scripting (XSS) attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the formatted HTML response
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", escapedKeyword)

	// Analytics support: Log the search keyword (simple implementation)
	if keyword != "" {
		log.Printf("Analytics: User searched for keyword: %q", keyword)
	}
}

func main() {
	// Register the handler function for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server is starting on http://localhost:8080/search?keyword=golang")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

