	// 3. Set the response Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Escape the user input to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// 5. Construct the HTML response
	// Fulfills the requirement: <h2>Search Results: [keyword]</h2>
	htmlResponse := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>

    <!-- Placeholder for actual product list -->
    <div>
        <p>Loading products matching your search...</p>
    </div>
</body>
</html>`, safeKeyword)

	// 6. Send the response
	w.WriteHeader(http.StatusOK)
	_, err := w.Write([]byte(htmlResponse))
	if err != nil {
		log.Printf("Error writing response: %v\n", err)
	}
}

